import React from 'react';
import { BrowserRouter, Routes, Route, useNavigate, useParams, Router } from 'react-router-dom';
import './App.css'
import UserAuth from './components/UserAuth';
import Home from './components/Home';
import Mood from './components/Mood';
import Journal from './components/Journal';
import Tasks from './components/Tasks';
import Dashboard from './components/Dashboard';
import History from './components/History';

function App() {
  return (
      // <Routes>
      //   <Route path="/home" element={<Home />} />
      //   <Route path="/" element={<UserAuth />} />

      //   {/* Journal route accepts optional id param for editing */}
      //   <Route path="/journal/:id?" element={<JournalWrapper />} />

      //   <Route path="/tasks" element={<Tasks />} />
      //   <Route path="/mood" element={<Mood />} />
      //   <Route path="/dashboard" element={<Dashboard />} />

      //   {/* History page with onEdit callback */}
      //   <Route path="/history" element={<HistoryWrapper />} />
      // </Routes>

      <Router>
        <Route path='/' element={<UserAuth/>}></Route>
      </Router>
  );
}

// Wrapper for History to inject edit handler and navigate to journal/:id
function HistoryWrapper() {
  const navigate = useNavigate();

  const handleEditEntry = (id) => {
    navigate(`/journal/${id}`);
  };

  return <History onEditEntry={handleEditEntry} />;
}

// Wrapper for Journal to get id param and pass down editEntryId
function JournalWrapper() {
  const { id } = useParams();
  const navigate = useNavigate();

  // After save or cancel, return to history page
  const onSaveComplete = () => {
    navigate('/history');
  };

  return <Journal editEntryId={id ? id : null} onSaveComplete={onSaveComplete} />;
}

export default App;
